const payload = $json;
const timestamp = new Date().toISOString();
const dateStr = new Date().toLocaleString('es-CO');

let output = `
╔════════════════════════════════════════════════════════════════╗
║     NEXUSRECOVER — HOSPITALITY NOTIFICATION                    ║
║                 IRROPS Decision Support System                  ║
╚════════════════════════════════════════════════════════════════╝

⏰ Timestamp: ${dateStr}
ID: ${payload.scenario_id || 'unknown'}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
DISRUPTION SUMMARY
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

🛫 Hub Airport:           ${payload.disruption_summary?.hub_airport || 'YYZ'}
⚠️  Event:                ${payload.disruption_summary?.event || 'Unknown'}

📊 Impact Summary:
   • Diverted flights:    ${payload.disruption_summary?.total_diverted_flights || 0}
   • PAX diverted:        ${payload.disruption_summary?.total_pax_diverted || 0}
   • PAX stranded at hub: ${payload.disruption_summary?.total_pax_stranded_at_hub || 0}

   Stranded breakdown:
   • Business class:      ${payload.disruption_summary?.pax_breakdown_stranded?.business || 0}
   • Economy class:       ${payload.disruption_summary?.pax_breakdown_stranded?.economy || 0}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
ALTERNATE AIRPORT OPERATIONS
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
`;

const altOps = payload.alternate_airport_ops || [];
const activeAlts = altOps.filter(a => a.status === 'ACTIVE');

if (activeAlts.length > 0) {
  for (let i = 0; i < activeAlts.length; i++) {
    const alt = activeAlts[i];
    output += `
┌─ ALTERNATE AIRPORT ${i + 1}: ${alt.iata} ──────────────────────────┐
│
│  Name:                    ${alt.name}
│  Status:                  ${alt.status}
│  
│  ✈️  Incoming Flights:
`;
    if (alt.incoming_flights && alt.incoming_flights.length > 0) {
      for (const flight of alt.incoming_flights) {
        output += `│    • ${flight.flight_id} from ${flight.origin} (${flight.aircraft}) - ETA ${flight.eta}\n`;
      }
    }
    output += `│  
│  👥 Passenger Summary:
│    • Total incoming:      ${alt.total_pax_incoming}
│    • Business class:      ${alt.pax_breakdown?.business || 0}
│    • Economy class:       ${alt.pax_breakdown?.economy || 0}
│  
│  🚌 Ground Transport:
│    • Provider:            ${alt.ground_transport?.provider_contact || 'TBD'}
│    • Vehicles required:   ${alt.ground_transport?.vehicles_required || 0}
│    • Pickup location:     ${alt.ground_transport?.pickup_airport || alt.iata}
│    • Drop-off:            ${alt.ground_transport?.drop_off || 'YYZ'}
│    • Transfer time:       ${alt.ground_transport?.estimated_transfer_min || 0} minutes
│    • Cost per PAX:        $${alt.ground_transport?.cost_per_pax_usd || 0}
│    • Total transport:     $${(alt.ground_transport?.total_transport_cost_usd || 0).toLocaleString('en-US')}
│    • Priority boarding:   ${alt.ground_transport?.priority_boarding || 'Standard'}
│  
│  📋 On-Site Requirements:
`;
    if (alt.on_site_requirements) {
      for (const req of alt.on_site_requirements) {
        output += `│    ✓ ${req}\n`;
      }
    }
    output += `│
└─────────────────────────────────────────────────────────┘
`;
  }
} else {
  output += `\n  (No active alternate airports)\n`;
}

output += `
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
STRANDED PASSENGERS AT HUB (${payload.stranded_pax_at_hub?.total_pax || 0} PAX)
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
`;

const stranded = payload.stranded_pax_at_hub || {};
if (stranded.total_pax > 0) {
  output += `
🏨 Hotel Requirements:
   • Total rooms needed:     ${stranded.hotel_rooms_required || 0} rooms
   • Hotel standard:         ${stranded.hotel_type_required || '3-4 star'}
   • Meals per PAX:          $${stranded.meal_vouchers?.value_per_pax_usd || 0}
   • Total meal vouchers:    ${stranded.meal_vouchers?.count || 0} × $${stranded.meal_vouchers?.value_per_pax_usd || 0}

👥 Passenger Groups:
`;
  if (stranded.groups && stranded.groups.length > 0) {
    for (const grp of stranded.groups) {
      output += `   • ${grp.group_id}: ${grp.count} ${grp.tier.toUpperCase()} PAX from ${grp.origin} → ${grp.missed_destination}\n`;
      output += `     Cost: $${(grp.total_stranding_cost_usd || 0).toLocaleString('en-US')}\n`;
    }
  }
} else {
  output += `\n  (No stranded passengers - all connections made)\n`;
}

output += `
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
YYZ HUB REQUIREMENTS
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
`;

const yyzReqs = payload.yyz_hub_requirements || {};
output += `
🎫 Lounge & Services:
   • Lounge activation:      ${yyzReqs.lounge_activation ? 'YES' : 'NO'}`;
if (yyzReqs.lounge_activation) {
  output += ` (${yyzReqs.lounge_pax_count || 0} Business PAX)`;
}
output += `
   • Service desks needed:   ${yyzReqs.customer_service_desks_needed || 0}

📋 Rebooking Priority:
`;
if (yyzReqs.rebooking_priority) {
  for (const priority of yyzReqs.rebooking_priority) {
    output += `   1️⃣  ${priority}\n`;
  }
}
output += `
📢 Passenger Announcement:
   "${yyzReqs.announcement_script || 'N/A'}"\n`;

output += `
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
COST SUMMARY
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
`;

const costs = payload.cost_summary || {};
output += `
💰 Hospitality Costs:
   • Ground transport:       $${(costs.ground_transport_total_usd || 0).toLocaleString('en-US')}
   • Stranded PAX (hotels):  $${(costs.stranded_pax_total_cost_usd || 0).toLocaleString('en-US')}
   ─────────────────────────
   • TOTAL:                  $${((costs.ground_transport_total_usd || 0) + (costs.stranded_pax_total_cost_usd || 0)).toLocaleString('en-US')}

`;

output += `╔════════════════════════════════════════════════════════════════╗
║ End of Hospitality Notification                                ║
║ Generated by: ${payload.issued_by || 'NexusRecover'}${' '.repeat(30 - (payload.issued_by || 'NexusRecover').length)}║
╚════════════════════════════════════════════════════════════════╝
`;

// Build HTML version for email
const hubAirport = payload.disruption_summary?.hub_airport || 'YYZ';
const event = payload.disruption_summary?.event || 'Unknown';
const totalDiverted = payload.disruption_summary?.total_diverted_flights || 0;
const paxDiverted = payload.disruption_summary?.total_pax_diverted || 0;
const paxStranded = payload.disruption_summary?.total_pax_stranded_at_hub || 0;
const businessStranded = payload.disruption_summary?.pax_breakdown_stranded?.business || 0;
const economyStranded = payload.disruption_summary?.pax_breakdown_stranded?.economy || 0;

let altAirportsHtml = '';
if (activeAlts.length > 0) {
  for (let i = 0; i < activeAlts.length; i++) {
    const alt = activeAlts[i];
    let flightsHtml = '';
    if (alt.incoming_flights && alt.incoming_flights.length > 0) {
      flightsHtml = alt.incoming_flights.map(f =>
        `<tr><td style="padding:4px 8px;border:1px solid #ddd;">${f.flight_id}</td><td style="padding:4px 8px;border:1px solid #ddd;">${f.origin}</td><td style="padding:4px 8px;border:1px solid #ddd;">${f.aircraft}</td><td style="padding:4px 8px;border:1px solid #ddd;">${f.eta}</td></tr>`
      ).join('');
    }
    let reqsHtml = '';
    if (alt.on_site_requirements) {
      reqsHtml = alt.on_site_requirements.map(r => `<li>${r}</li>`).join('');
    }
    altAirportsHtml += `
    <div style="background:#f8f9fa;border-left:4px solid #0d6efd;padding:12px 16px;margin:8px 0;border-radius:4px;">
      <h3 style="margin:0 0 8px 0;color:#0d6efd;">Alternate ${i+1}: ${alt.iata} &mdash; ${alt.name}</h3>
      <p><strong>Status:</strong> ${alt.status}</p>
      ${flightsHtml ? `<table style="border-collapse:collapse;width:100%;margin:8px 0;"><thead><tr style="background:#e9ecef;"><th style="padding:4px 8px;border:1px solid #ddd;text-align:left;">Flight</th><th style="padding:4px 8px;border:1px solid #ddd;text-align:left;">Origin</th><th style="padding:4px 8px;border:1px solid #ddd;text-align:left;">Aircraft</th><th style="padding:4px 8px;border:1px solid #ddd;text-align:left;">ETA</th></tr></thead><tbody>${flightsHtml}</tbody></table>` : ''}
      <p><strong>PAX:</strong> ${alt.total_pax_incoming} total (Business: ${alt.pax_breakdown?.business || 0} | Economy: ${alt.pax_breakdown?.economy || 0})</p>
      <p><strong>Ground Transport:</strong> ${alt.ground_transport?.vehicles_required || 0} vehicles, ${alt.ground_transport?.estimated_transfer_min || 0} min transfer, $${(alt.ground_transport?.total_transport_cost_usd || 0).toLocaleString('en-US')} total</p>
      ${reqsHtml ? `<p><strong>On-Site Requirements:</strong></p><ul>${reqsHtml}</ul>` : ''}
    </div>`;
  }
} else {
  altAirportsHtml = '<p style="color:#6c757d;">No active alternate airports</p>';
}

let strandedHtml = '';
if (stranded.total_pax > 0) {
  let groupsHtml = '';
  if (stranded.groups && stranded.groups.length > 0) {
    groupsHtml = stranded.groups.map(g =>
      `<tr><td style="padding:4px 8px;border:1px solid #ddd;">${g.group_id}</td><td style="padding:4px 8px;border:1px solid #ddd;">${g.count}</td><td style="padding:4px 8px;border:1px solid #ddd;">${g.tier.toUpperCase()}</td><td style="padding:4px 8px;border:1px solid #ddd;">${g.origin} &rarr; ${g.missed_destination}</td><td style="padding:4px 8px;border:1px solid #ddd;">$${(g.total_stranding_cost_usd || 0).toLocaleString('en-US')}</td></tr>`
    ).join('');
  }
  strandedHtml = `
    <p><strong>Rooms needed:</strong> ${stranded.hotel_rooms_required || 0} | <strong>Standard:</strong> ${stranded.hotel_type_required || '3-4 star'} | <strong>Meal vouchers:</strong> ${stranded.meal_vouchers?.count || 0} x $${stranded.meal_vouchers?.value_per_pax_usd || 0}</p>
    ${groupsHtml ? `<table style="border-collapse:collapse;width:100%;margin:8px 0;"><thead><tr style="background:#e9ecef;"><th style="padding:4px 8px;border:1px solid #ddd;text-align:left;">Group</th><th style="padding:4px 8px;border:1px solid #ddd;text-align:left;">Count</th><th style="padding:4px 8px;border:1px solid #ddd;text-align:left;">Tier</th><th style="padding:4px 8px;border:1px solid #ddd;text-align:left;">Route</th><th style="padding:4px 8px;border:1px solid #ddd;text-align:left;">Cost</th></tr></thead><tbody>${groupsHtml}</tbody></table>` : ''}`;
} else {
  strandedHtml = '<p style="color:#6c757d;">No stranded passengers - all connections made</p>';
}

const groundTotal = (costs.ground_transport_total_usd || 0);
const strandedTotal = (costs.stranded_pax_total_cost_usd || 0);
const grandTotal = groundTotal + strandedTotal;

let rebookingHtml = '';
if (yyzReqs.rebooking_priority) {
  rebookingHtml = '<ol>' + yyzReqs.rebooking_priority.map(p => `<li>${p}</li>`).join('') + '</ol>';
}

const htmlBody = `
<div style="font-family:'Segoe UI',Arial,sans-serif;max-width:700px;margin:0 auto;color:#212529;">
  <div style="background:linear-gradient(135deg,#1a1a2e,#16213e);color:white;padding:24px 32px;border-radius:8px 8px 0 0;">
    <h1 style="margin:0;font-size:22px;">NexusRecover &mdash; Hospitality Notification</h1>
    <p style="margin:4px 0 0 0;opacity:0.8;font-size:13px;">IRROPS Decision Support System</p>
  </div>

  <div style="padding:24px 32px;border:1px solid #dee2e6;border-top:none;">
    <p style="color:#6c757d;font-size:13px;margin-top:0;">${dateStr} | Scenario: ${payload.scenario_id || 'unknown'}</p>

    <h2 style="color:#dc3545;border-bottom:2px solid #dc3545;padding-bottom:8px;">Disruption Summary</h2>
    <table style="width:100%;margin-bottom:16px;">
      <tr><td style="padding:4px 0;"><strong>Hub Airport:</strong></td><td>${hubAirport}</td></tr>
      <tr><td style="padding:4px 0;"><strong>Event:</strong></td><td>${event}</td></tr>
      <tr><td style="padding:4px 0;"><strong>Diverted Flights:</strong></td><td>${totalDiverted}</td></tr>
      <tr><td style="padding:4px 0;"><strong>PAX Diverted:</strong></td><td>${paxDiverted}</td></tr>
      <tr><td style="padding:4px 0;"><strong>PAX Stranded at Hub:</strong></td><td>${paxStranded} (Business: ${businessStranded} | Economy: ${economyStranded})</td></tr>
    </table>

    <h2 style="color:#0d6efd;border-bottom:2px solid #0d6efd;padding-bottom:8px;">Alternate Airport Operations</h2>
    ${altAirportsHtml}

    <h2 style="color:#fd7e14;border-bottom:2px solid #fd7e14;padding-bottom:8px;">Stranded Passengers at Hub (${stranded.total_pax || 0} PAX)</h2>
    ${strandedHtml}

    <h2 style="color:#6f42c1;border-bottom:2px solid #6f42c1;padding-bottom:8px;">YYZ Hub Requirements</h2>
    <p><strong>Lounge Activation:</strong> ${yyzReqs.lounge_activation ? 'YES (' + (yyzReqs.lounge_pax_count || 0) + ' Business PAX)' : 'NO'}</p>
    <p><strong>Service Desks Needed:</strong> ${yyzReqs.customer_service_desks_needed || 0}</p>
    ${rebookingHtml ? '<p><strong>Rebooking Priority:</strong></p>' + rebookingHtml : ''}
    ${yyzReqs.announcement_script ? '<div style="background:#fff3cd;border:1px solid #ffc107;padding:12px;border-radius:4px;margin:8px 0;"><strong>Passenger Announcement:</strong><br>"' + yyzReqs.announcement_script + '"</div>' : ''}

    <h2 style="color:#198754;border-bottom:2px solid #198754;padding-bottom:8px;">Cost Summary</h2>
    <table style="width:100%;">
      <tr><td style="padding:4px 0;"><strong>Ground Transport:</strong></td><td style="text-align:right;">$${groundTotal.toLocaleString('en-US')}</td></tr>
      <tr><td style="padding:4px 0;"><strong>Stranded PAX (Hotels):</strong></td><td style="text-align:right;">$${strandedTotal.toLocaleString('en-US')}</td></tr>
      <tr style="border-top:2px solid #212529;font-size:18px;"><td style="padding:8px 0;"><strong>TOTAL:</strong></td><td style="text-align:right;"><strong>$${grandTotal.toLocaleString('en-US')}</strong></td></tr>
    </table>
  </div>

  <div style="background:#f8f9fa;padding:12px 32px;border:1px solid #dee2e6;border-top:none;border-radius:0 0 8px 8px;text-align:center;">
    <p style="margin:0;color:#6c757d;font-size:12px;">Generated by ${payload.issued_by || 'NexusRecover'} | IRROPS Decision Support System</p>
  </div>
</div>`;

const emailSubject = `[IRROPS] Hospitality Alert: ${event} at ${hubAirport} — ${paxDiverted} PAX diverted, ${paxStranded} stranded`;

return { formattedText: output, htmlBody: htmlBody, emailSubject: emailSubject };
